// NewAuthorizePayload builds a cliAuth service authorize endpoint payload.
func NewAuthorizePayload(body *AuthorizeRequestBody, sessionToken *string) *cliauth.AuthorizePayload {
	v := &cliauth.AuthorizePayload{
		CodeChallenge:       *body.CodeChallenge,
		CodeChallengeMethod: *body.CodeChallengeMethod,
		ProjectSlug:         body.ProjectSlug,
	}
	v.SessionToken = sessionToken

	return v
}

// NewRedeemPayload builds a cliAuth service redeem endpoint payload.
func NewRedeemPayload(body *RedeemRequestBody) *cliauth.RedeemPayload {
	v := &cliauth.RedeemPayload{
		Code:         *body.Code,
		CodeVerifier: *body.CodeVerifier,
	}

	return v
}

// ValidateAuthorizeRequestBody runs the validations defined on
// AuthorizeRequestBody
func ValidateAuthorizeRequestBody(body *AuthorizeRequestBody) (err error) {
	if body.CodeChallenge == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("code_challenge", "body"))
	}
	if body.CodeChallengeMethod == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("code_challenge_method", "body"))
	}
	if body.CodeChallenge != nil {
		if utf8.RuneCountInString(*body.CodeChallenge) < 43 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.code_challenge", *body.CodeChallenge, utf8.RuneCountInString(*body.CodeChallenge), 43, true))
		}
	}
	if body.CodeChallenge != nil {
		if utf8.RuneCountInString(*body.CodeChallenge) > 128 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.code_challenge", *body.CodeChallenge, utf8.RuneCountInString(*body.CodeChallenge), 128, false))
		}
	}
	if body.CodeChallengeMethod != nil {
		if !(*body.CodeChallengeMethod == "S256") {
			err = goa.MergeErrors(err, goa.InvalidEnumValueError("body.code_challenge_method", *body.CodeChallengeMethod, []any{"S256"}))
		}
	}
	return
}

// ValidateRedeemRequestBody runs the validations defined on RedeemRequestBody
func ValidateRedeemRequestBody(body *RedeemRequestBody) (err error) {
	if body.Code == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("code", "body"))
	}
	if body.CodeVerifier == nil {
		err = goa.MergeErrors(err, goa.MissingFieldError("code_verifier", "body"))
	}
	if body.CodeVerifier != nil {
		if utf8.RuneCountInString(*body.CodeVerifier) < 43 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.code_verifier", *body.CodeVerifier, utf8.RuneCountInString(*body.CodeVerifier), 43, true))
		}
	}
	if body.CodeVerifier != nil {
		if utf8.RuneCountInString(*body.CodeVerifier) > 128 {
			err = goa.MergeErrors(err, goa.InvalidLengthError("body.code_verifier", *body.CodeVerifier, utf8.RuneCountInString(*body.CodeVerifier), 128, false))
		}
	}
	return
}
